const PROFANITY_KO = ['바보', '멍청', '씨발', '개새끼', '지랄'];
const PROFANITY_EN = ['fuck', 'shit', 'asshole', 'idiot', 'bitch'];
const SELF_HARM = ['자해', '자살', '죽고 싶', 'kill myself', 'self harm', 'suicide'];

const body = $input.first().json.body || {};
const text = (body.text || '').trim();
const userLocale = body.user_locale || 'ko';
if (!text) return [{ json: { valid: false, reason: 'empty_text', systemPrompt: '', userPrompt: '' } }];
const lower = text.toLowerCase();
for (const word of SELF_HARM) if (lower.includes(word)) return [{ json: { valid: false, reason: 'self_harm', systemPrompt: '', userPrompt: '' } }];
for (const word of [...PROFANITY_KO, ...PROFANITY_EN]) if (lower.includes(word)) return [{ json: { valid: false, reason: 'profanity', systemPrompt: '', userPrompt: '' } }];

const systemPrompt = [
  'You are a JSON schedule parser. Output ONLY a single JSON object — NO reasoning, NO explanation, NO markdown.',
  'Keys: title (string), start_time (ISO8601 or null), end_time (ISO8601 or null), category (one of: work, study, hobby, health, etc), tags (string array), confidence (0.0-1.0).',
  'If start/end unknown, use null. If uncertain about fields, set confidence low and tags empty.',
  `Locale: ${userLocale}.`
].join('\n');

return [{ json: { valid: true, text, userLocale, systemPrompt, userPrompt: text } }];

const res = $input.first().json;
let content = '';
if (typeof res.text === 'string') content = res.text;
else if (res.output && typeof res.output === 'object') content = JSON.stringify(res.output);
else if (typeof res.response === 'string') content = res.response;
else content = JSON.stringify(res);
content = content.trim();
if (content.startsWith('```')) {
  content = content.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?```\s*$/, '').trim();
}
let parsed;
try { parsed = JSON.parse(content); } catch (e) { parsed = null; }
if (!parsed || typeof parsed.title !== 'string') {
  return [{ json: { title: '', start_time: null, end_time: null, category: 'etc', tags: [], confidence: 0.0, source: 'preset' } }];
}
return [{ json: {
  title: parsed.title,
  start_time: parsed.start_time ?? null,
  end_time: parsed.end_time ?? null,
  category: ['work','study','hobby','health','etc'].includes(parsed.category) ? parsed.category : 'etc',
  tags: Array.isArray(parsed.tags) ? parsed.tags.map(String) : [],
  confidence: typeof parsed.confidence === 'number' ? Math.max(0, Math.min(1, parsed.confidence)) : 0.0,
  source: 'llm'
}}];
